'use strict';
class DashboardRouter{
static#instance=null;
static#TRANSITION_MS=250;
static#PREFETCH_DELAY=100;
static#PREFETCH_TTL=30_000;
static#SWIPE_THRESHOLD=80;
static#CACHE_LIMIT=8;
static#DASHBOARD_RE=/^\/(?:dashboard(?:\/(?:lender|borrower|history|loan\/\d+))?|tools\/create|tools\/\d+\/edit|profile\/\d+|bookmarks|events)$/;
#mainEl;
#cache=new Map();
#currentAbort=null;#navigating=false;#navId=0;#navIndex=0;#hoverTimer=null;#swipeStartX=0;#swipeStartY=0;#currentUrl=location.href;#abortController=new AbortController();
constructor(mainEl){
this.#mainEl=mainEl;
if(matchMedia('(prefers-reduced-motion: reduce)').matches){
NT.style.setRule('dash-reduced-motion',':root','--_dash-transition-ms:0ms');}
history.replaceState({dashNav:true,idx:this.#navIndex},'');
this.#bind();}
static init(){
if(DashboardRouter.#instance)return DashboardRouter.#instance;
if(!window.NT)return null;
const mainEl=document.getElementById('main-content');
if(!mainEl)return null;
return(DashboardRouter.#instance=new DashboardRouter(mainEl));}
destroy(){
clearTimeout(this.#hoverTimer);
this.#currentAbort?.abort();
this.#abortController.abort();
NT.style.removeRule('dash-reduced-motion');
DashboardRouter.#instance=null;}#bind(){
const{signal}=this.#abortController;
this.#mainEl.addEventListener('click',this.#handleClick,{signal});
window.addEventListener('popstate',this.#handlePopstate,{signal});
this.#mainEl.addEventListener('pointerenter',this.#handlePointerEnter,{signal,capture:true});
this.#mainEl.addEventListener('pointerleave',this.#handlePointerLeave,{signal,capture:true});
this.#mainEl.addEventListener('focusin',this.#handleFocusIn,{signal});
this.#mainEl.addEventListener('focusout',this.#handleFocusOut,{signal});
document.addEventListener('keydown',this.#handleKeydown,{signal});
this.#mainEl.addEventListener('touchstart',this.#handleTouchStart,{signal,passive:true});
this.#mainEl.addEventListener('touchend',this.#handleTouchEnd,{signal,passive:true});}
static#isDashboardUrl(url){
try{
const path=new URL(url,location.origin).pathname;
return DashboardRouter.#DASHBOARD_RE.test(path);}catch{return false;}}
static#shouldIntercept(link){
if(!link?.href)return false;
if(link.target==='_blank'||link.hasAttribute('download'))return false;
return DashboardRouter.#isDashboardUrl(link.href);}
#cacheGet(url){
const entry=this.#cache.get(url);
if(!entry)return null;
if(Date.now()-entry.time>=DashboardRouter.#PREFETCH_TTL){
this.#cache.delete(url);
return null;}
return entry.data;}#cacheSet(url,data){
if(this.#cache.size>=DashboardRouter.#CACHE_LIMIT){
const oldest=this.#cache.keys().next().value;
this.#cache.delete(oldest);}
this.#cache.set(url,{data,time:Date.now()});}
async#fetchPage(url,signal){
const cached=this.#cacheGet(url);
if(cached)return cached;
const response=await NT.fetch(url,{
signal,
timeout:8_000,
headers:{Accept:'text/html','X-Requested-With':'XMLHttpRequest'},});
if(!response.ok)return null;
const text=await response.text();
const doc=new DOMParser().parseFromString(text,'text/html');
const isPartial=response.headers.get('X-Partial')==='1';
if(isPartial){
const title=decodeURIComponent(response.headers.get('X-Page-Title')??'');
const cssHeader=response.headers.get('X-Page-Css')??'';
const stylesheets=cssHeader?cssHeader.split(',').map((s)=>s.trim()):[];
const jsHeader=response.headers.get('X-Page-Js')??'';
const scripts=jsHeader?jsHeader.split(',').map((s)=>s.trim()):[];
const data={doc,title,stylesheets,scripts,partial:true};
this.#cacheSet(url,data);
return data;}
const newMain=doc.getElementById('main-content');
if(!newMain)return null;
const stylesheets=[...doc.querySelectorAll('link[rel="stylesheet"]')]
.map((link)=>link.getAttribute('href'))
.filter(Boolean);
const scripts=[...doc.querySelectorAll('script[src]')]
.map((s)=>s.getAttribute('src'))
.filter(Boolean);
const data={doc,title:doc.title,stylesheets,scripts,partial:false};
this.#cacheSet(url,data);
return data;}
static#syncStylesheets(needed){
const current=new Set(
[...document.querySelectorAll('head link[rel="stylesheet"]')]
.map((l)=>l.getAttribute('href'))
.filter(Boolean),);
const loads=[];
for(const href of needed){
if(current.has(href))continue;
const link=document.createElement('link');
link.rel='stylesheet';
link.href=href;
loads.push(new Promise((resolve)=>{
link.onload=resolve;
link.onerror=resolve;}));
document.head.appendChild(link);}
return loads.length>0?Promise.all(loads):Promise.resolve();}
static async#syncScripts(needed){
const current=new Set(
[...document.querySelectorAll('head script[src]')]
.map((s)=>s.getAttribute('src'))
.filter(Boolean),);
for(const src of needed){
if(current.has(src))continue;
await new Promise((resolve)=>{
const script=document.createElement('script');
script.src=src;
script.onload=resolve;
script.onerror=resolve;
document.head.appendChild(script);});}}#reinit(){
NT.applyFocalPoints();
for(const flash of this.#mainEl.querySelectorAll('[data-flash]')){
const type=flash.getAttribute('data-flash');
NT.toast(flash.textContent.trim(),type);
flash.remove();}
for(const input of this.#mainEl.querySelectorAll('input[data-suggest="tools"]')){
if(!input.id)continue;
const availableOnly=input.hasAttribute('data-available-only');
NT.autosuggest({
inputId:input.id,
fetchUrl:(q)=>`/tools/suggest?q=${encodeURIComponent(q)}${availableOnly ? '&available=1' : ''}`,
labelKey:'name',
onSelect:(item)=>{window.location.href=`/tools/${item.id}`;},});}
for(const img of this.#mainEl.querySelectorAll('img[loading="lazy"]')){
if(img.complete&&img.naturalWidth>0){
img.setAttribute('data-loaded','');}else{
img.addEventListener('load',()=>img.setAttribute('data-loaded',''),{once:true});}}
document.dispatchEvent(new CustomEvent('dashboard:content-swapped'));}
#updateNavActiveState(url){
const nav=document.querySelector('[data-dashboard-body] > nav');
if(!nav)return;
const path=new URL(url,location.origin).pathname;
for(const a of nav.querySelectorAll('a[aria-current]')){
a.removeAttribute('aria-current');}
const match=nav.querySelector(`a[href="${CSS.escape(path)}"]`)
??nav.querySelector(`a[href="${CSS.escape(path.replace(/\/\d+$/, ''))}"]`);
match?.setAttribute('aria-current','page');}
async#navigate(url,direction='forward',pushHistory=true){
if(this.#navigating)return;
this.#navigating=true;
const id=++this.#navId;
const abort=new AbortController();
this.#currentAbort=abort;
const slideOut=direction==='back'?'slide-out-right':'slide-out-left';
const slideIn=direction==='back'?'slide-in-left':'slide-in-right';
try{
const outDoc=new DOMParser().parseFromString(
`<div id="main-content">${this.#mainEl.innerHTML}</div>`,'text/html',);
this.#cacheSet(this.#currentUrl,{
doc:outDoc,
title:document.title,
stylesheets:[...document.querySelectorAll('head link[rel="stylesheet"]')]
.map((l)=>l.getAttribute('href'))
.filter(Boolean),
scripts:[...document.querySelectorAll('head script[src]')]
.map((s)=>s.getAttribute('src'))
.filter(Boolean),
partial:false,});
const[data]=await Promise.all([
this.#fetchPage(url,abort.signal),
new Promise((resolve)=>{
this.#mainEl.setAttribute('data-transition',slideOut);
this.#mainEl.addEventListener('transitionend',resolve,{once:true});
setTimeout(resolve,DashboardRouter.#TRANSITION_MS+50);}),]);
if(!data){
this.#mainEl.removeAttribute('data-transition');
location.assign(url);
return;}
if(pushHistory){
this.#navIndex++;
history.pushState({dashNav:true,idx:this.#navIndex},'',url);}
window.scrollTo({top:0,behavior:'instant'});
await DashboardRouter.#syncStylesheets(data.stylesheets);
if(data.partial){
this.#mainEl.replaceChildren(...Array.from(data.doc.body.childNodes));}else{
const newMain=data.doc.getElementById('main-content');
this.#mainEl.replaceChildren(...Array.from(newMain.childNodes));}
document.title=data.title;
this.#currentUrl=url;
this.#updateNavActiveState(url);
await DashboardRouter.#syncScripts(data.scripts);
this.#navigating=false;
this.#currentAbort=null;
this.#mainEl.setAttribute('data-transition',slideIn);
requestAnimationFrame(()=>{
requestAnimationFrame(()=>{
if(id===this.#navId){
this.#mainEl.removeAttribute('data-transition');}});});
this.#reinit();}catch(err){
if(err.name!=='AbortError'){
this.#mainEl.removeAttribute('data-transition');
location.assign(url);}}finally{
if(id===this.#navId){
this.#navigating=false;
this.#currentAbort=null;}}}
#handleClick=(e)=>{
if(e.ctrlKey||e.metaKey||e.shiftKey||e.altKey)return;
const link=e.target.closest('a[href]');
if(!link)return;
if(link.closest('form'))return;
const isBack=!!link.closest('nav[aria-label="Back"]');
if(isBack){
e.preventDefault();
if(this.#navIndex>0){
history.back();}else{
const dest=DashboardRouter.#isDashboardUrl(link.href)?link.href:'/dashboard';
this.#navigate(dest,'back');}
return;}
if(!DashboardRouter.#shouldIntercept(link))return;
e.preventDefault();
this.#navigate(link.href,'forward');};#handlePopstate=(e)=>{
if(!e.state?.dashNav){
if(DashboardRouter.#isDashboardUrl(location.href)){
location.reload();}
return;}
if(!DashboardRouter.#isDashboardUrl(location.href)){
location.reload();
return;}
const direction=(e.state.idx??0)<this.#navIndex?'back':'forward';
this.#navIndex=e.state.idx??0;
this.#navigate(location.href,direction,false);};#startPrefetch(link){
if(!DashboardRouter.#shouldIntercept(link))return;
if(this.#cache.has(link.href))return;
this.#hoverTimer=setTimeout(()=>{
this.#fetchPage(link.href).catch(()=>{});},DashboardRouter.#PREFETCH_DELAY);}#cancelPrefetch(){
clearTimeout(this.#hoverTimer);
this.#hoverTimer=null;}#handlePointerEnter=(e)=>{
const link=e.target.closest('a[href]');
if(link)this.#startPrefetch(link);};#handlePointerLeave=(e)=>{
if(e.target.closest('a[href]'))this.#cancelPrefetch();};#handleFocusIn=(e)=>{
const link=e.target.closest('a[href]');
if(link)this.#startPrefetch(link);};#handleFocusOut=(e)=>{
if(e.target.closest('a[href]'))this.#cancelPrefetch();};
#handleKeydown=(e)=>{
if(!e.altKey||e.key!=='ArrowLeft')return;
if(e.ctrlKey||e.metaKey||e.shiftKey)return;
const backLink=this.#mainEl.querySelector('nav[aria-label="Back"] a[href]');
if(!backLink||!DashboardRouter.#shouldIntercept(backLink))return;
e.preventDefault();
this.#navigate(backLink.href,'back');};
#handleTouchStart=(e)=>{
if(e.touches.length!==1)return;
this.#swipeStartX=e.touches[0].clientX;
this.#swipeStartY=e.touches[0].clientY;};
#handleTouchEnd=(e)=>{
if(e.changedTouches.length!==1)return;
const dx=e.changedTouches[0].clientX-this.#swipeStartX;
const dy=Math.abs(e.changedTouches[0].clientY-this.#swipeStartY);
if(dx<DashboardRouter.#SWIPE_THRESHOLD||dx<dy*2)return;
const backLink=this.#mainEl.querySelector('nav[aria-label="Back"] a[href]');
if(!backLink||!DashboardRouter.#shouldIntercept(backLink))return;
this.#navigate(backLink.href,'back');};}
class ProfilePhotoManager{
static#instance=null;
#container;
#fileInput;
#focalXInput;
#focalYInput;
#previewImg;#abortController=new AbortController();
constructor(container){
this.#container=container;
this.#fileInput=container.querySelector('input[type="file"]');
this.#focalXInput=container.querySelector('input[name="focal_x"]');
this.#focalYInput=container.querySelector('input[name="focal_y"]');
this.#previewImg=container.querySelector('figure img');
this.#bind();}
static init(){
if(ProfilePhotoManager.#instance)return ProfilePhotoManager.#instance;
const container=document.querySelector('[data-profile-photo-upload]');
if(!container)return null;
return(ProfilePhotoManager.#instance=new ProfilePhotoManager(container));}
destroy(){
this.#abortController.abort();
ProfilePhotoManager.#instance=null;}
static teardown(){
ProfilePhotoManager.#instance?.destroy();}#bind(){
const{signal}=this.#abortController;
this.#fileInput.addEventListener('change',this.#handleFileChange,{signal});
const repoBtn=this.#container.querySelector('[data-reposition-photo]');
repoBtn?.addEventListener('click',this.#handleReposition,{signal});
const removeBtn=this.#container.querySelector('[data-remove-photo]');
removeBtn?.addEventListener('click',this.#handleRemovePhoto,{signal});
if(NT.crop){
NT.crop.onConfirm((mode,data)=>{
if(mode==='upload'){
const dt=new DataTransfer();
dt.items.add(data.file);
this.#fileInput.files=dt.files;
this.#focalXInput.value=data.focalX;
this.#focalYInput.value=data.focalY;
this.#showPreview(data.file,data.focalX,data.focalY);
this.#selectPhotoRadio(data.file,data.focalX,data.focalY);
NT.crop.close();}else if(mode==='reposition'){
this.#handleRepositionConfirm(data.focalX,data.focalY);}});}}#handleFileChange=()=>{
const file=this.#fileInput.files?.[0];
if(!file)return;
this.#fileInput.value='';
if(!ProfilePhotoManager.#validateFile(file))return;
if(NT.crop){
NT.crop.openUpload(file,{icon:'fa-solid fa-camera',label:'Set Photo',aspectRatio:1});}};#handleReposition=()=>{
if(!this.#previewImg||!NT.crop)return;
const fx=parseInt(this.#previewImg.dataset.focalX,10)||50;
const fy=parseInt(this.#previewImg.dataset.focalY,10)||50;
NT.crop.openReposition(this.#previewImg.src,fx,fy,'profile',{aspectRatio:1});};#handleRemovePhoto=async()=>{
const response=await NT.fetch('/profile/image/delete',{method:'POST'});
if(response.ok){
window.location.reload();}else{
NT.toast('Failed to remove photo.','error');}};
async#handleRepositionConfirm(focalX,focalY){
NT.crop.setConfirmState(true,true);
try{
const response=await NT.fetch('/profile/image',{
method:'PATCH',
body:JSON.stringify({focal_x:focalX,focal_y:focalY}),});
if(!response.ok){
NT.toast('Failed to update photo position.','error');
NT.crop.setConfirmState(false,false);
return;}
this.#focalXInput.value=focalX;
this.#focalYInput.value=focalY;
if(this.#previewImg){
this.#previewImg.dataset.focalX=focalX;
this.#previewImg.dataset.focalY=focalY;
NT.applyFocalPoints(this.#container);}
NT.crop.close();}catch{
NT.toast('Failed to update photo position.','error');
NT.crop.setConfirmState(false,false);}}
static async#createThumbnail(file,size,focalX,focalY){
const source=await createImageBitmap(file);
const canvas=new OffscreenCanvas(size,size);
const ctx=canvas.getContext('2d');
const sw=source.width;
const sh=source.height;
const crop=Math.min(sw,sh);
const cx=Math.round((sw-crop)*(focalX/100));
const cy=Math.round((sh-crop)*(focalY/100));
ctx.drawImage(source,cx,cy,crop,crop,0,0,size,size);
source.close();
const blob=await canvas.convertToBlob({type:'image/jpeg',quality:0.92});
return URL.createObjectURL(blob);}
async#showPreview(file,focalX,focalY){
const url=await ProfilePhotoManager.#createThumbnail(file,240,focalX,focalY);
this.#applyPreviewUrl(url,focalX,focalY);}
#applyPreviewUrl(url,focalX,focalY){
if(this.#previewImg){
this.#previewImg.src=url;
this.#previewImg.dataset.focalX=focalX;
this.#previewImg.dataset.focalY=focalY;
NT.applyFocalPoints(this.#container);}else{
const figure=document.createElement('figure');
const img=document.createElement('img');
img.src=url;
img.alt='Photo preview';
img.width=120;
img.height=120;
figure.append(img);
const controlDiv=this.#container.querySelector('div');
if(controlDiv)controlDiv.before(figure);
else this.#container.prepend(figure);
this.#previewImg=img;}}
async#selectPhotoRadio(file,focalX,focalY){
const fieldset=this.#container.closest('fieldset');
if(!fieldset)return;
let grid=fieldset.querySelector('[data-avatar-grid]');
if(!grid){
const heading=document.createElement('p');
heading.dataset.avatarHeading='';
heading.textContent='Choose your display avatar';
grid=document.createElement('div');
grid.dataset.avatarGrid='';
grid.setAttribute('role','radiogroup');
grid.setAttribute('aria-label','Display avatar selection');
fieldset.append(heading,grid);}
const thumbUrl=await ProfilePhotoManager.#createThumbnail(file,128,focalX,focalY);
let radio=grid.querySelector('input[name="avatar_vector"][value="photo"]');
if(!radio){
const label=document.createElement('label');
label.dataset.photoChoice='';
radio=document.createElement('input');
radio.type='radio';
radio.name='avatar_vector';
radio.value='photo';
const span=document.createElement('span');
const img=document.createElement('img');
img.src=thumbUrl;
img.alt='My photo';
img.width=64;
img.height=64;
img.decoding='async';
span.append(img);
const small=document.createElement('small');
small.textContent='My Photo';
label.append(radio,span,small);
grid.prepend(label);}else{
const img=radio.closest('label')?.querySelector('img');
if(img)img.src=thumbUrl;}
radio.checked=true;}
static#validateFile(file){
const allowed=['image/jpeg','image/png','image/webp'];
if(!allowed.includes(file.type)){
NT.toast('Invalid file type. Use JPEG, PNG, or WebP.','error');
return false;}
if(file.size>5*1024*1024){
NT.toast('File exceeds the 5 MB limit.','error');
return false;}
return true;}}
DashboardRouter.init();
ProfilePhotoManager.init();
document.addEventListener('dashboard:content-swapped',()=>{
ProfilePhotoManager.teardown();
if(typeof ImageCrop!=='undefined')ImageCrop.reinit();
ProfilePhotoManager.init();});